function convertWhoopToWIASleep(whoopSleep, whoopRecovery) {
  const totalSleepMs = whoopSleep.slow_wave_sleep_duration_milli + 
                       whoopSleep.light_sleep_duration_milli + 
                       whoopSleep.rem_sleep_duration_milli;

  return {
    recordId: generateUUID(),
    subjectId: whoopSleep.user_id,
    timestamp: whoopSleep.end,
    dataSource: 'consumer_wearable',
    sleepArchitecture: {
      summary: {
        totalSleepTime_min: totalSleepMs / 60000,
        sleepEfficiency_pct: whoopSleep.sleep_efficiency_percentage,
        sleepOnsetLatency_min: whoopSleep.latency_milli / 60000,
        wakeAfterSleepOnset_min: whoopSleep.disturbances_milli / 60000
      },
      stagePercentages: {
        n1_pct: 0,
        n2_pct: (whoopSleep.light_sleep_duration_milli / totalSleepMs) * 100,
        n3_sws_pct: (whoopSleep.slow_wave_sleep_duration_milli / totalSleepMs) * 100,
        rem_pct: (whoopSleep.rem_sleep_duration_milli / totalSleepMs) * 100
      },
      cycleCount: whoopSleep.sleep_cycle_count
    },
    circadianMarkers: {
      heartRateVariability: {
        rmssd: whoopRecovery?.hrv_rmssd_milli
      }
    }
  };
}
